团队业绩快照
1：首先我会给几个地址并且标注或标记；
2：查询所有标记或标注地址的直推人数量，团队成员数量，团队质押总量
3：根据提供的标记或标注地址向上查推荐人，​如果推荐人也被标记；如果标记的地址之间存在直接或间接邀请关系；
确定标记地址邀请关系最近的两个地址，根据邀请关系，邀请人和被邀请人；新增一个字段显示邀请人有效质押总量；有效质押总量逻辑是 ：邀请人团队质押总量减去被邀请人的质押总量
4：做个定时任务每天北京时间24点或0点同步一次数据，目前数据同步在本地只保留最近7天的，这个最好设计一个统计接口，方便后面切换到远程数据库，程序启动的时候查询今天的有没有同步，没有同步的话支持手动按钮同步
5：需要开发成网站，需要统计可视化展示最近一周内每天和一周的数据和变化
6：如果标记地址A邀请了未标记地址W,w邀请了标记地址B，b又间接或直接邀请了标记地址c
a的有效业绩是 A的团队质押总量 - B的团队质押总量（仅扣距离最近1一个被邀请人的团队质押总量）
b的有效业绩是 B的团队质押总量 - 减去c团队的质押总量
7：前端技术选择最好能适配部署到https://vercel.com/ 平台
8：支持添加和标记新地址，支持地址和标注全部导出
9：安全检查，从标记向上查推荐人的时候，一直查到推荐人地址是0地址时结束
10：有的标记地址在向上查询推荐人的时候，对应上了，避免再次重复查询解决资源
查询部分核心逻辑代码参考
// 获取团队成员，返回示例：{ directReferralQuantity: 21, teamNumber: '6444' } 直推邀请人数（directReferralQuantity），团队成员数量（teamNumber）
function fetchInviteData(address) {
  const url = `https://apiv2.ocros.io/api/v1/communities/getInviteData?address=${address}&level=undefined`;
  return fetch(url, {
    "headers": {
      "accept": "application/json, text/plain, */*",
      "accept-language": "zh-CN,zh;q=0.9,en;q=0.8,en-GB;q=0.7,en-US;q=0.6",
      "if-none-match": "W/\"31-IaTgHtIXJ+pl9JyA8IrHE8sMDoM\"",
      "priority": "u=1, i",
      "sec-fetch-dest": "empty",
      "sec-fetch-mode": "cors",
      "sec-fetch-site": "cross-site",
      "Referer": "https://origindefi.io/",
      "Referrer-Policy": "strict-origin-when-cross-origin"
    },
    "body": null,
    "method": "GET"
  }).then(res => res.json()).then(data => console.log(data));
}

// 用法示例
fetchInviteData("0x889B7750F0466a7D009399F52C3449FD3968411c");
// 查询团队质押总量，返回结果示例{ teamStaking: 1899172276949564, role: 'Disciple' } 团队质押总量（teamStaking），代币符号 LGNS,代币精度是9
function fetchStakingStatus(address) {
  fetch(`https://api.ocros.io/v1/api/comm/queryStakingStatus?member=${address}`, {
    "headers": {
      "accept": "*/*",
      "accept-language": "zh-CN,zh;q=0.9,en;q=0.8,en-GB;q=0.7,en-US;q=0.6",
      "cache-control": "max-age=0",
      "content-type": "application/json",
      "priority": "u=1, i",
      "sec-fetch-dest": "empty",
      "sec-fetch-mode": "cors",
      "sec-fetch-site": "cross-site",
      "Referer": "https://origindefi.io/",
      "Referrer-Policy": "strict-origin-when-cross-origin"
    },
    "body": null,
    "method": "POST"
  }).then(res => res.json()).then(data => console.log(data));
}

// 用法示例
fetchStakingStatus("0x889B7750F0466a7D009399F52C3449FD3968411c");
const address = "0x889B7750F0466a7D009399F52C3449FD3968411c";
const addressParam = address.replace(/^0x/, '').toLowerCase().padStart(64, '0');
const data = "0x08ae4b0c" + addressParam;

fetch("https://greatest-powerful-feather.matic.quiknode.pro/d05012eaa00b33a3aa3e8e7981b2d658f4281815/", {
  "headers": {
    "accept": "*/*",
    "accept-language": "zh-CN,zh;q=0.9,en;q=0.8,en-GB;q=0.7,en-US;q=0.6",
    "cache-control": "max-age=0",
    "content-type": "application/json",
    "priority": "u=1, i",
    "sec-fetch-dest": "empty",
    "sec-fetch-mode": "cors",
    "sec-fetch-site": "cross-site",
    "Referer": "https://origindefi.io/",
    "Referrer-Policy": "strict-origin-when-cross-origin"
  },
  "body": JSON.stringify({
    "method": "eth_call",
    "params": [
      {
        "to": "0x6757165973042541ebdec47b73283397b5afd90e",
        "data": data
      },
      "latest"
    ],
    "id": 44,
    "jsonrpc": "2.0"
  }),
  "method": "POST"
}).then(res => res.json()).then(resData => {

    // 解析referrer地址
    const result = resData.result;
    if (result) {
        const hex = result.startsWith("0x") ? result.slice(2) : result;
        // members方法：返回前64为level，后64为address
        const referrerHex = hex.slice(64, 128); // 取第2个64字符
        const referrer = '0x' + referrerHex.slice(24); // 地址取后40位
        // 常见EVM响应都为小写，可转大写
        const referrerAddr = referrer.slice(0, 2) + referrer.slice(2).toUpperCase();
        console.log("推荐人地址:", referrerAddr);
    } else {
        console.log("无有效响应:", resData);
    }
});

