export interface TrackedAddress {
  address: string;
  label: string;
}

export interface StakingData {
  teamStaking: string; // BigInt as string
  role: string;
}

export interface InviteData {
  directReferralQuantity: number;
  teamNumber: string;
}

export interface AddressMetrics extends TrackedAddress {
  directReferrals: number;
  teamNumber: number;
  teamStaking: number; // Formatted to decimal
  effectiveStaking: number;
  referrer: string | null;
  nearestLabeledChildren: string[]; // Addresses of children used for effective staking deduction
}

export interface Snapshot {
  date: string; // YYYY-MM-DD
  data: AddressMetrics[];
}

export interface DailySummary {
  date: string;
  totalTeamStaking: number;
  totalEffectiveStaking: number;
  totalMembers: number;
}

import { InviteData, StakingData } from '../types';

const PRECISION = 9;

export const formatStaking = (raw: string | number): number => {
  const val = typeof raw === 'string' ? BigInt(raw) : BigInt(Math.floor(raw));
  return Number(val) / Math.pow(10, PRECISION);
};

export const fetchInviteData = async (address: string): Promise<InviteData> => {
  const url = `https://apiv2.ocros.io/api/v1/communities/getInviteData?address=${address}&level=undefined`;
  const res = await fetch(url, {
    headers: {
      "accept": "application/json",
      "Referer": "https://origindefi.io/",
    }
  });
  return res.json();
};

export const fetchStakingStatus = async (address: string): Promise<StakingData> => {
  const res = await fetch(`https://api.ocros.io/v1/api/comm/queryStakingStatus?member=${address}`, {
    method: "POST",
    headers: {
      "content-type": "application/json",
      "Referer": "https://origindefi.io/",
    }
  });
  return res.json();
};

export const fetchReferrer = async (address: string): Promise<string | null> => {
  const addressParam = address.replace(/^0x/, '').toLowerCase().padStart(64, '0');
  const data = "0x08ae4b0c" + addressParam;

  try {
    const res = await fetch("https://greatest-powerful-feather.matic.quiknode.pro/d05012eaa00b33a3aa3e8e7981b2d658f4281815/", {
      method: "POST",
      headers: {
        "content-type": "application/json",
        "Referer": "https://origindefi.io/",
      },
      body: JSON.stringify({
        "method": "eth_call",
        "params": [
          {
            "to": "0x6757165973042541ebdec47b73283397b5afd90e",
            "data": data
          },
          "latest"
        ],
        "id": 44,
        "jsonrpc": "2.0"
      })
    });

    const resData = await res.json();
    const result = resData.result;
    if (result && result !== '0x') {
      const hex = result.startsWith("0x") ? result.slice(2) : result;
      // members method: returns level (64 chars) then address (64 chars)
      if (hex.length < 128) return null;
      const referrerHex = hex.slice(64, 128);
      const referrer = '0x' + referrerHex.slice(24);

      const zeroAddr = '0x' + '0'.repeat(40);
      if (referrer.toLowerCase() === zeroAddr) return null;

      // Standardize format
      return '0x' + referrer.slice(2).toLowerCase();
    }
  } catch (error) {
    console.error("Referrer fetch error:", error);
  }
  return null;
};

/**
 * Traces the referral chain up to the zero address or a max limit.
 */
export const fetchFullChain = async (
  address: string, 
  cache: Map<string, string | null> = new Map()
): Promise<string[]> => {
  const chain: string[] = [];
  let current: string | null = address.toLowerCase();
  const maxDepth = 100;

  while (current && chain.length < maxDepth) {
    let next: string | null;
    if (cache.has(current)) {
      next = cache.get(current)!;
    } else {
      next = await fetchReferrer(current);
      cache.set(current, next);
    }

    if (!next) break;
    chain.push(next);
    current = next;
  }
  return chain;
};

import { TrackedAddress, Snapshot } from '../types';

const STORAGE_KEY_ADDRESSES = 'team_snapshot_addresses';
const STORAGE_KEY_SNAPSHOTS = 'team_snapshot_history';

export const getTrackedAddresses = (): TrackedAddress[] => {
  const stored = localStorage.getItem(STORAGE_KEY_ADDRESSES);
  return stored ? JSON.parse(stored) : [];
};

export const saveTrackedAddresses = (addresses: TrackedAddress[]) => {
  localStorage.setItem(STORAGE_KEY_ADDRESSES, JSON.stringify(addresses));
};

export const getSnapshots = (): Snapshot[] => {
  const stored = localStorage.getItem(STORAGE_KEY_SNAPSHOTS);
  return stored ? JSON.parse(stored) : [];
};

export const saveSnapshot = (snapshot: Snapshot) => {
  let snapshots = getSnapshots();
  // Filter out any existing snapshot for the same date
  snapshots = snapshots.filter(s => s.date !== snapshot.date);
  snapshots.push(snapshot);

  // Keep only last 7 days
  snapshots.sort((a, b) => b.date.localeCompare(a.date));
  if (snapshots.length > 7) {
    snapshots = snapshots.slice(0, 7);
  }

  localStorage.setItem(STORAGE_KEY_SNAPSHOTS, JSON.stringify(snapshots));
};

export const deleteSnapshot = (date: string) => {
  let snapshots = getSnapshots();
  snapshots = snapshots.filter(s => s.date !== date);
  localStorage.setItem(STORAGE_KEY_SNAPSHOTS, JSON.stringify(snapshots));
};

