import React, { useState, useEffect, useCallback } from 'react';
import { 
  TrackedAddress, 
  AddressMetrics, 
  Snapshot, 
  DailySummary 
} from './types';
import * as db from './services/dbService';
import * as api from './services/apiService';
import SummaryCards from './components/SummaryCards';
import TrendChart from './components/TrendChart';
import AddressTable from './components/AddressTable';

const App: React.FC = () => {
  const [addresses, setAddresses] = useState<TrackedAddress[]>([]);
  const [snapshots, setSnapshots] = useState<Snapshot[]>([]);
  const [isLoading, setIsLoading] = useState(false);
  const [newAddr, setNewAddr] = useState('');
  const [newLabel, setNewLabel] = useState('');
  const [lastSyncDate, setLastSyncDate] = useState<string | null>(null);

  useEffect(() => {
    setAddresses(db.getTrackedAddresses());
    const history = db.getSnapshots();
    setSnapshots(history);
    if (history.length > 0) {
      setLastSyncDate(history[0].date);
    }
  }, []);

  const runSync = async () => {
    if (addresses.length === 0) {
      alert("请先添加需要追踪的地址");
      return;
    }

    setIsLoading(true);
    try {
      const today = new Date().toISOString().split('T')[0];
      const referralCache = new Map<string, string | null>();

      // 1. Fetch raw data for all addresses
      const rawData = await Promise.all(addresses.map(async (item) => {
        const [invite, stake, chain] = await Promise.all([
          api.fetchInviteData(item.address),
          api.fetchStakingStatus(item.address),
          api.fetchFullChain(item.address, referralCache)
        ]);

        return {
          ...item,
          directReferrals: invite.directReferralQuantity,
          teamNumber: parseInt(invite.teamNumber || '0'),
          teamStaking: api.formatStaking(stake.teamStaking),
          referrerChain: chain,
          referrer: chain[0] || null
        };
      }));

      // 2. Identify nearest labeled descendants for effective staking deduction
      // Logic: For address A, find all labeled addresses B such that A is B's ancestor.
      // Filter out those where another labeled address C exists on the path between A and B.
      const metrics: AddressMetrics[] = rawData.map(A => {
        const nearestChildren: string[] = [];
        const otherLabeledAddresses = rawData.filter(X => X.address.toLowerCase() !== A.address.toLowerCase());

        otherLabeledAddresses.forEach(B => {
          // Check if A is an ancestor of B
          if (B.referrerChain.some(anc => anc.toLowerCase() === A.address.toLowerCase())) {
            // Find path between B and A in B's referral chain
            const idx = B.referrerChain.findIndex(anc => anc.toLowerCase() === A.address.toLowerCase());
            const pathBetween = B.referrerChain.slice(0, idx); // Addresses between B and A

            // Check if any labeled address exists on the path between
            const isNearest = !pathBetween.some(mid => 
              otherLabeledAddresses.some(label => label.address.toLowerCase() === mid.toLowerCase())
            );

            if (isNearest) {
              nearestChildren.push(B.address);
            }
          }
        });

        const childrenStaking = nearestChildren.reduce((acc, childAddr) => {
          const childData = rawData.find(r => r.address.toLowerCase() === childAddr.toLowerCase());
          return acc + (childData ? childData.teamStaking : 0);
        }, 0);

        return {
          address: A.address,
          label: A.label,
          directReferrals: A.directReferrals,
          teamNumber: A.teamNumber,
          teamStaking: A.teamStaking,
          effectiveStaking: Math.max(0, A.teamStaking - childrenStaking),
          referrer: A.referrer,
          nearestLabeledChildren: nearestChildren
        };
      });

      const newSnapshot: Snapshot = {
        date: today,
        data: metrics
      };

      db.saveSnapshot(newSnapshot);
      const updatedHistory = db.getSnapshots();
      setSnapshots(updatedHistory);
      setLastSyncDate(today);
    } catch (err) {
      console.error(err);
      alert("同步失败，请检查网络或控制台。");
    } finally {
      setIsLoading(false);
    }
  };

  const handleAddAddress = () => {
    if (!newAddr || !newLabel) return;
    if (addresses.some(a => a.address.toLowerCase() === newAddr.toLowerCase())) {
      alert("该地址已存在");
      return;
    }
    const updated = [...addresses, { address: newAddr.trim(), label: newLabel.trim() }];
    setAddresses(updated);
    db.saveTrackedAddresses(updated);
    setNewAddr('');
    setNewLabel('');
  };

  const handleRemoveAddress = (addr: string) => {
    const updated = addresses.filter(a => a.address !== addr);
    setAddresses(updated);
    db.saveTrackedAddresses(updated);
  };

  const exportData = () => {
    const csvContent = "data:text/csv;charset=utf-8," 
      + "Label,Address\n"
      + addresses.map(e => `${e.label},${e.address}`).join("\n");
    const encodedUri = encodeURI(csvContent);
    const link = document.createElement("a");
    link.setAttribute("href", encodedUri);
    link.setAttribute("download", `team_addresses_${new Date().toISOString().split('T')[0]}.csv`);
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

  const todayStr = new Date().toISOString().split('T')[0];
  const currentSnapshot = snapshots.find(s => s.date === todayStr) || snapshots[0];

  const dailySummary: DailySummary = currentSnapshot ? {
    date: currentSnapshot.date,
