      alert("该地址已存在");
      return;
    }
    const updated = [...addresses, { address: newAddr.trim(), label: newLabel.trim() }];
    setAddresses(updated);
    db.saveTrackedAddresses(updated);
    setNewAddr('');
    setNewLabel('');
  };

  const handleRemoveAddress = (addr: string) => {
    const updated = addresses.filter(a => a.address !== addr);
