    totalEffectiveStaking: currentSnapshot.data.reduce((acc, d) => acc + d.effectiveStaking, 0),
    totalMembers: currentSnapshot.data.reduce((acc, d) => acc + d.teamNumber, 0)
  } : {
    date: todayStr,
    totalTeamStaking: 0,
    totalEffectiveStaking: 0,
    totalMembers: 0
  };

  return (
