            <div className="p-8 max-h-[60vh] overflow-y-auto">
              <div className="space-y-4">
                <div className="flex items-start space-x-3">
                  <div className="w-3 h-3 bg-blue-600 rounded-full mt-1.5 shrink-0 ring-4 ring-blue-50"></div>
                  <div>
                    <div className="text-xs text-blue-600 font-bold uppercase">当前查询地址</div>
                    <div className="font-semibold text-slate-900">{getAddressLabel(showPathModal.address) || '当前地址'}</div>
                    <div className="text-xs text-slate-400 font-mono">{showPathModal.address}</div>
                  </div>
                </div>
                {showPathModal.chain.map((addr, idx) => (
                  <div key={addr} className="flex items-start space-x-3 relative">
                    <div className="absolute left-1.5 -top-4 w-0.5 h-4 bg-slate-100"></div>
                    <div className={`w-3 h-3 ${getAddressLabel(addr) ? 'bg-emerald-500' : 'bg-slate-200'} rounded-full mt-1.5 shrink-0`}></div>
                    <div>
                      <div className="text-xs text-slate-400">第 {idx + 1} 级推荐人</div>
