                      </div>
                      <div className="text-xs text-slate-400 font-mono">{addr}</div>
                    </div>
                  </div>
                ))}
                <div className="flex items-start space-x-3 relative">
                  <div className="absolute left-1.5 -top-4 w-0.5 h-4 bg-slate-100"></div>
                  <div className="w-3 h-3 bg-slate-800 rounded-full mt-1.5 shrink-0"></div>
                  <div className="font-semibold text-slate-400 text-sm">根节点 (0x000...)</div>
                </div>
              </div>
            </div>
          </div>
        </div>
      )}

      {/* Global Querying Indicator */}
      {(isLoading || isPathLoading) && (
        <div className="fixed bottom-8 right-8 bg-slate-900 text-white px-6 py-3 rounded-full shadow-2xl z-50 flex items-center space-x-3">
          <svg className="animate-spin h-4 w-4 text-white" fill="none" viewBox="0 0 24 24"><circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle><path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path></svg>
          <span className="text-sm font-medium">{isPathLoading ? '正在查询路径溯源...' : '数据处理中...'}</span>
        </div>
      )}
    </div>
  );
};

