import { createClient } from '@supabase/supabase-js';

// 请确保在环境中配置了以下变量。此处使用 process.env 访问。
const supabaseUrl = (process.env as any).SUPABASE_URL || '';
const supabaseAnonKey = (process.env as any).SUPABASE_ANON_KEY || '';

export const supabase = createClient(supabaseUrl, supabaseAnonKey);

import { TrackedAddress, Snapshot } from '../types';
import { supabase } from './supabaseClient';

export const getTrackedAddresses = async (): Promise<TrackedAddress[]> => {
  const { data, error } = await supabase
    .from('tracked_addresses')
    .select('*');

  if (error) {
    console.error('Fetch addresses error:', error);
    return [];
  }
  return data.map(item => ({
    address: item.address,
    label: item.label,
    warZone: item.war_zone
  }));
};

export const saveTrackedAddress = async (addr: TrackedAddress) => {
  const { error } = await supabase
    .from('tracked_addresses')
    .upsert({
      address: addr.address.toLowerCase(),
      label: addr.label,
      war_zone: addr.warZone
    });
  if (error) throw error;
};

export const deleteTrackedAddress = async (address: string) => {
  const { error } = await supabase
    .from('tracked_addresses')
    .delete()
    .eq('address', address.toLowerCase());
  if (error) throw error;
};

export const getSnapshots = async (): Promise<Snapshot[]> => {
  const sevenDaysAgo = new Date();
  sevenDaysAgo.setDate(sevenDaysAgo.getDate() - 7);
  const dateStr = sevenDaysAgo.toISOString().split('T')[0];

  const { data, error } = await supabase
    .from('snapshots')
    .select('*')
    .gte('date', dateStr)
    .order('date', { ascending: false });

  if (error) {
    console.error('Fetch snapshots error:', error);
    return [];
  }

  // 按日期分组汇总
  const grouped = data.reduce((acc: Record<string, any[]>, curr) => {
    if (!acc[curr.date]) acc[curr.date] = [];
    acc[curr.date].push({
      ...curr.metrics,
      address: curr.address,
      date: curr.date
    });
    return acc;
  }, {});

  return Object.keys(grouped).map(date => ({
    date,
    data: grouped[date]
  }));
};

export const saveSnapshotRecord = async (address: string, date: string, metrics: any) => {
  const { error } = await supabase
    .from('snapshots')
    .upsert({
      address: address.toLowerCase(),
      date: date,
      metrics: metrics
    }, { onConflict: 'address,date' });

  if (error) throw error;
};

// 自动清理7天前的数据可以作为 Supabase Edge Functions 或由前端同步时触发
export const cleanupOldSnapshots = async () => {
  const sevenDaysAgo = new Date();
  sevenDaysAgo.setDate(sevenDaysAgo.getDate() - 7);
  const dateStr = sevenDaysAgo.toISOString().split('T')[0];

  await supabase
    .from('snapshots')
    .delete()
    .lt('date', dateStr);
};

import React, { useState, useEffect, useMemo } from 'react';
import { 
  TrackedAddress, 
  AddressMetrics, 
  Snapshot 
} from './types';
import * as db from './services/dbService';
import * as api from './services/apiService';
import AddressTable from './components/AddressTable';

const App: React.FC = () => {
  const [addresses, setAddresses] = useState<TrackedAddress[]>([]);
  const [snapshots, setSnapshots] = useState<Snapshot[]>([]);
  const [isLoading, setIsLoading] = useState(false);
  const [isPathLoading, setIsPathLoading] = useState(false);

  // Input states
  const [newAddr, setNewAddr] = useState('');
  const [newLabel, setNewLabel] = useState('');
  const [newWarZone, setNewWarZone] = useState('1');
  const [searchTerm, setSearchTerm] = useState('');

  // Modal states
  const [showHistoryModal, setShowHistoryModal] = useState<AddressMetrics | null>(null);
  const [showPathModal, setShowPathModal] = useState<{address: string, chain: string[]} | null>(null);
  const [lastSyncDate, setLastSyncDate] = useState<string | null>(null);

  const loadData = async () => {
    setIsLoading(true);
    try {
      const [addrs, history] = await Promise.all([
        db.getTrackedAddresses(),
        db.getSnapshots()
      ]);
      setAddresses(addrs);
      setSnapshots(history);
      if (history.length > 0) {
        setLastSyncDate(history[0].date);
      }
    } finally {
      setIsLoading(false);
    }
  };

  useEffect(() => {
    loadData();
  }, []);

  const runSync = async () => {
    if (addresses.length === 0) {
      alert("请先添加需要追踪的地址");
      return;
    }

    setIsLoading(true);
    try {
      const today = new Date().toISOString().split('T')[0];
      const referralCache = new Map<string, string | null>();

      // 1. 获取所有地址的最新数据
      const rawData = await Promise.all(addresses.map(async (item) => {
        const [invite, stake, chain] = await Promise.all([
          api.fetchInviteData(item.address),
          api.fetchStakingStatus(item.address),
          api.fetchFullChain(item.address, referralCache)
        ]);

        return {
          ...item,
          directReferrals: invite.directReferralQuantity,
          teamNumber: parseInt(invite.teamNumber || '0'),
          teamStaking: api.formatStaking(stake.teamStaking),
          referrerChain: chain,
          referrer: chain[0] || null
        };
      }));

      // 2. 计算有效业绩
      const metrics: AddressMetrics[] = rawData.map(A => {
        const nearestChildren: string[] = [];
        const otherLabeledAddresses = rawData.filter(X => X.address.toLowerCase() !== A.address.toLowerCase());

        otherLabeledAddresses.forEach(B => {
          if (B.referrerChain.some(anc => anc.toLowerCase() === A.address.toLowerCase())) {
            const idx = B.referrerChain.findIndex(anc => anc.toLowerCase() === A.address.toLowerCase());
            const pathBetween = B.referrerChain.slice(0, idx);
            const isNearest = !pathBetween.some(mid => 
              otherLabeledAddresses.some(label => label.address.toLowerCase() === mid.toLowerCase())
            );
            if (isNearest) {
              nearestChildren.push(B.address);
            }
          }
        });

        const childrenStaking = nearestChildren.reduce((acc, childAddr) => {
          const childData = rawData.find(r => r.address.toLowerCase() === childAddr.toLowerCase());
          return acc + (childData ? childData.teamStaking : 0);
        }, 0);

        return {
          address: A.address,
          label: A.label,
          warZone: A.warZone,
          directReferrals: A.directReferrals,
          teamNumber: A.teamNumber,
          teamStaking: A.teamStaking,
          effectiveStaking: Math.max(0, A.teamStaking - childrenStaking),
          referrer: A.referrer,
          nearestLabeledChildren: nearestChildren
        };
      });

      // 3. 保存至 Supabase
      await Promise.all(metrics.map(m => {
        const { address, label, warZone, ...rest } = m;
        return db.saveSnapshotRecord(m.address, today, {
          ...rest,
          label,
          warZone
        });
      }));

      // 4. 清理旧数据并重载
      await db.cleanupOldSnapshots();
      await loadData();
      alert("今日数据同步完成");
    } catch (err) {
      console.error(err);
      alert("同步失败，请检查 Supabase 配置或网络。");
    } finally {
      setIsLoading(false);
    }
  };

  const handleAddAddress = async () => {
    if (!newAddr || !newLabel) return;
    if (addresses.some(a => a.address.toLowerCase() === newAddr.toLowerCase())) {
      alert("该地址已存在");
      return;
    }
    const item: TrackedAddress = { address: newAddr.trim(), label: newLabel.trim(), warZone: newWarZone };
    setIsLoading(true);
    try {
      await db.saveTrackedAddress(item);
      await loadData();
      setNewAddr('');
      setNewLabel('');
    } finally {
      setIsLoading(false);
    }
  };

  const handleRemoveAddress = async (addr: string) => {
    if (!confirm('确定移除此地址及其历史数据吗？')) return;
    setIsLoading(true);
    try {
      await db.deleteTrackedAddress(addr);
      await loadData();
    } finally {
      setIsLoading(false);
    }
  };

  const filteredData = useMemo(() => {
    const todayStr = new Date().toISOString().split('T')[0];
    const latest = snapshots.find(s => s.date === todayStr) || snapshots[0];
    if (!latest) return [];

    return latest.data.filter(item => {
      const matchLabel = item.label.toLowerCase().includes(searchTerm.toLowerCase());
      const matchAddr = item.address.toLowerCase().includes(searchTerm.toLowerCase());
      const matchWarZone = item.warZone?.toLowerCase().includes(searchTerm.toLowerCase());
      return matchLabel || matchAddr || matchWarZone;
    });
  }, [snapshots, searchTerm]);

  const fetchPath = async (address: string) => {
    setIsPathLoading(true);
    try {
      const chain = await api.fetchFullChain(address);
      setShowPathModal({ address, chain });
    } catch (err) {
      alert("获取路径失败");
    } finally {
      setIsPathLoading(false);
    }
  };

  const getAddressLabel = (addr: string) => {
    const found = addresses.find(a => a.address.toLowerCase() === addr.toLowerCase());
    return found ? found.label : null;
  };

  const exportData = () => {
    const csvContent = "data:text/csv;charset=utf-8," 
      + "WarZone,Label,Address\n"
      + addresses.map(e => `${e.warZone || ''},${e.label},${e.address}`).join("\n");
    const encodedUri = encodeURI(csvContent);
    const link = document.createElement("a");
    link.setAttribute("href", encodedUri);
    link.setAttribute("download", `team_snapshot_${new Date().toISOString().split('T')[0]}.csv`);
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

  return (
    <div className="min-h-screen pb-12 bg-slate-50">
      <header className="bg-white border-b border-slate-200 sticky top-0 z-30 shadow-sm">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 h-16 flex items-center justify-between">
          <div className="flex items-center space-x-3">
            <div className="w-8 h-8 bg-blue-600 rounded-lg flex items-center justify-center text-white font-bold text-sm">OS</div>
            <h1 className="text-lg font-bold text-slate-900">团队业绩快照 (Supabase 版)</h1>
          </div>
          <div className="flex items-center space-x-4">
            <span className="text-xs text-slate-500 hidden sm:block">
              最后同步: {lastSyncDate || '从未'}
            </span>
            <button
              onClick={runSync}
              disabled={isLoading}
              className={`px-4 py-2 rounded-lg text-sm font-semibold transition-all shadow-sm ${
                isLoading 
                  ? 'bg-slate-100 text-slate-400 cursor-not-allowed' 
                  : 'bg-blue-600 text-white hover:bg-blue-700 active:scale-95'
              }`}
            >
              {isLoading ? '同步中...' : '同步今日数据'}
            </button>
          </div>
        </div>
      </header>

      <main className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-8">
        {/* Input & Search Section */}
        <section className="space-y-6">
          <div className="bg-white p-6 rounded-xl shadow-sm border border-slate-200">
            <h2 className="text-sm font-bold text-slate-800 mb-4 uppercase tracking-wider">添加追踪地址</h2>
            <div className="grid grid-cols-1 md:grid-cols-4 lg:grid-cols-5 gap-4">
              <div className="md:col-span-1">
                <label className="block text-xs font-medium text-slate-500 mb-1 uppercase">战区</label>
                <div className="relative">
                  <select 
                    value={newWarZone} 
                    onChange={(e) => setNewWarZone(e.target.value)}
                    className="w-full pl-3 pr-10 py-2 text-sm border border-slate-300 rounded-lg bg-white focus:ring-2 focus:ring-blue-500 focus:border-blue-500 appearance-none transition-all"
                  >
                    {[1,2,3,4,5].map(v => <option key={v} value={v}>{v} 战区</option>)}
                    <option value="custom">手动输入...</option>
                  </select>
                  {newWarZone === 'custom' && (
                    <input 
                      type="text" 
                      placeholder="输入战区"
                      onChange={(e) => setNewWarZone(e.target.value)}
                      className="absolute inset-0 w-full px-3 py-2 text-sm border border-slate-300 rounded-lg bg-white focus:ring-2 focus:ring-blue-500"
                    />
                  )}
                </div>
              </div>
              <div className="md:col-span-1">
                <label className="block text-xs font-medium text-slate-500 mb-1 uppercase">标注名称</label>
                <input
